#include <stdio.h>
#include <stdint.h>

/*
 * Adder Circuit Implementation in C
 * Demonstrates Half Adder, Full Adder, and N-Bit Adder
 * Using bitwise operations to simulate hardware behavior
 */

/* Half Adder: Adds two single bits */
void half_adder(int a, int b, int *sum, int *carry) {
 *sum = a ^ b; // XOR gate for sum output
 *carry = a & b; // AND gate for carry output
}

/* Full Adder: Adds three bits (A, B, Carry-In) */
void full_adder(int a, int b, int cin, int *sum, int *cout) {
 // Sum = A XOR B XOR Cin (three-input XOR)
 *sum = a ^ b ^ cin;

 // Carry Out = (A AND B) OR (A AND Cin) OR (B AND Cin)
 *cout = (a & b) | (a & cin) | (b & cin);
}

/* N-Bit Ripple Carry Adder */
/* Returns sum as unsigned integer and carry out */
uint32_t n_bit_adder(uint32_t a, uint32_t b, int n, int *carry_out) {
 int carry = 0;
 uint32_t result = 0;

 for (int i = 0; i < n; i++) {
 int bit_a = (a >> i) & 1; // Extract i-th bit of A
 int bit_b = (b >> i) & 1; // Extract i-th bit of B
 int sum, cout;

 full_adder(bit_a, bit_b, carry, &sum, &cout);

 if (sum) {
 result |= (1 << i); // Set i-th bit of result
 }
 carry = cout;
 }

 *carry_out = carry;
 return result;
}

/* Print Half Adder Truth Table */
void print_half_adder_truth_table() {
 int a, b, sum, carry;

 printf("=== HALF ADDER TRUTH TABLE ===\n");
 printf("A B | S C\n");
 printf("-----------------\n");

 for (a = 0; a <= 1; a++) {
 for (b = 0; b <= 1; b++) {
 half_adder(a, b, &sum, &carry);
 printf("%d %d | %d %d\n", a, b, sum, carry);
 }
 }
}

/* Print Full Adder Truth Table */
void print_full_adder_truth_table() {
 int a, b, cin, sum, cout;

 printf("\n=== FULL ADDER TRUTH TABLE ===\n");
 printf("A B Cin | S Cout\n");
 printf("---------------------\n");

 for (a = 0; a <= 1; a++) {
 for (b = 0; b <= 1; b++) {
 for (cin = 0; cin <= 1; cin++) {
 full_adder(a, b, cin, &sum, &cout);
 printf("%d %d %d | %d %d\n", a, b, cin, sum, cout);
 }
 }
 }
}

/* Test N-Bit Adders */
void test_n_bit_adders() {
 int carry_out;
 uint32_t result;

 printf("\n=== 4-BIT ADDER TESTS ===\n");

 // Test 1: 5 + 3 = 8 (0101 + 0011 = 1000)
 result = n_bit_adder(5, 3, 4, &carry_out);
 printf("Test 1: 5 + 3\n");
 printf(" Result = %u, Carry Out = %d\n", result, carry_out);
 printf(" Expected: Result = 8, Carry = 0\n\n");

 // Test 2: 7 + 9 = 16 (0111 + 1001 = 10000)
 result = n_bit_adder(7, 9, 4, &carry_out);
 printf("Test 2: 7 + 9\n");
 printf(" Result = %u, Carry Out = %d\n", result, carry_out);
 printf(" Expected: Result = 0, Carry = 1 (overflow to 5th bit)\n\n");

 // Test 3: 15 + 1 = 16 (1111 + 0001 = 10000)
 result = n_bit_adder(15, 1, 4, &carry_out);
 printf("Test 3: 15 + 1\n");
 printf(" Result = %u, Carry Out = %d\n", result, carry_out);
 printf(" Expected: Result = 0, Carry = 1 (overflow)\n\n");

 // Test 4: 8-bit addition with overflow
 result = n_bit_adder(200, 100, 8, &carry_out);
 printf("Test 4: 200 + 100 (8-bit)\n");
 printf(" Result = %u, Carry Out = %d\n", result, carry_out);
 printf(" Expected: Result = 44, Carry = 1 (300 mod 256 = 44)\n");
}

int main() {
 print_half_adder_truth_table();
 print_full_adder_truth_table();
 test_n_bit_adders();

 return 0;
}

/**
 * Adder Circuit Implementation in Java
 * Implements Half Adder, Full Adder, and N-Bit Adder
 * Demonstrates object-oriented approach to digital circuit modeling
 */

public class AdderClasses {

 // ==================== HALF ADDER ====================
 static class HalfAdder {
 private int sum;
 private int carry;

 public void compute(int a, int b) {
 this.sum = a ^ b; // XOR gate
 this.carry = a & b; // AND gate
 }

 public int getSum() { return sum; }
 public int getCarry() { return carry; }

 @Override
 public String toString() {
 return "Sum=" + sum + ", Carry=" + carry;
 }
 }

 // ==================== FULL ADDER ====================
 static class FullAdder {
 private int sum;
 private int carryOut;

 public void compute(int a, int b, int cin) {
 // Sum = A XOR B XOR Cin
 this.sum = a ^ b ^ cin;

 // Carry Out = (A AND B) OR (A AND Cin) OR (B AND Cin)
 this.carryOut = (a & b) | (a & cin) | (b & cin);
 }

 public int getSum() { return sum; }
 public int getCarryOut() { return carryOut; }

 @Override
 public String toString() {
 return "Sum=" + sum + ", CarryOut=" + carryOut;
 }
 }

 // ==================== N-BIT ADDER ====================
 static class NBitAdder {
 private int numBits;
 private int[] sumBits;
 private int carryOut;

 public NBitAdder(int numBits) {
 this.numBits = numBits;
 this.sumBits = new int[numBits];
 }

 public void compute(int[] aBits, int[] bBits, int cin) {
 int carry = cin;
 FullAdder fa = new FullAdder();

 for (int i = 0; i < numBits; i++) {
 fa.compute(aBits[i], bBits[i], carry);
 sumBits[i] = fa.getSum();
 carry = fa.getCarryOut();
 }
 this.carryOut = carry;
 }

 public int[] getSumBits() { return sumBits; }
 public int getCarryOut() { return carryOut; }

 // Convert bit array to integer value
 public int toInteger(int[] bits) {
 int result = 0;
 for (int i = 0; i < bits.length; i++) {
 result |= (bits[i] << i);
 }
 return result;
 }

 public String bitsToString(int[] bits) {
 StringBuilder sb = new StringBuilder("[");
 for (int i = 0; i < bits.length; i++) {
 sb.append(bits[i]);
 if (i < bits.length - 1) sb.append(", ");
 }
 sb.append("]");
 return sb.toString();
 }
 }

 // ==================== MAIN METHOD ====================
 public static void main(String[] args) {
 // Test Half Adder
 System.out.println("=== HALF ADDER TRUTH TABLE ===");
 System.out.println("A B | S C");
 System.out.println("-----------------");

 HalfAdder ha = new HalfAdder();
 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 ha.compute(a, b);
 System.out.println(a + " " + b + " | " + ha.getSum() + " " + ha.getCarry());
 }
 }

 // Test Full Adder
 System.out.println("\n=== FULL ADDER TRUTH TABLE ===");
 System.out.println("A B Cin | S Cout");
 System.out.println("---------------------");

 FullAdder fa = new FullAdder();
 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 for (int cin = 0; cin <= 1; cin++) {
 fa.compute(a, b, cin);
 System.out.println(a + " " + b + " " + cin + " | " + fa.getSum() + " " + fa.getCarryOut());
 }
 }
 }

 // Test N-Bit Adder
 System.out.println("\n=== 4-BIT ADDER TESTS ===");

 NBitAdder adder4 = new NBitAdder(4);

 // Test 1: 5 + 3 = 8
 int[] a1 = {1, 0, 1, 0}; // 0101 = 5
 int[] b1 = {1, 1, 0, 0}; // 0011 = 3
 adder4.compute(a1, b1, 0);
 System.out.println("Test 1: 5 + 3");
 System.out.println(" A bits: " + adder4.bitsToString(a1));
 System.out.println(" B bits: " + adder4.bitsToString(b1));
 System.out.println(" Sum bits: " + adder4.bitsToString(adder4.getSumBits()));
 System.out.println(" Carry out: " + adder4.getCarryOut());
 System.out.println(" Decimal: " + adder4.toInteger(adder4.getSumBits()));

 // Test 2: 7 + 9 = 16 (overflow)
 int[] a2 = {1, 1, 1, 0}; // 0111 = 7
 int[] b2 = {1, 0, 0, 1}; // 1001 = 9
 adder4.compute(a2, b2, 0);
 System.out.println("\nTest 2: 7 + 9 (overflow)");
 System.out.println(" Sum bits: " + adder4.bitsToString(adder4.getSumBits()));
 System.out.println(" Carry out: " + adder4.getCarryOut());
 System.out.println(" Expected: Sum=0000, Carry=1");

 // Test 3: 15 + 1 = 16 (overflow)
 int[] a3 = {1, 1, 1, 1}; // 1111 = 15
 int[] b3 = {1, 0, 0, 0}; // 0001 = 1
 adder4.compute(a3, b3, 0);
 System.out.println("\nTest 3: 15 + 1 (overflow)");
 System.out.println(" Sum bits: " + adder4.bitsToString(adder4.getSumBits()));
 System.out.println(" Carry out: " + adder4.getCarryOut());
 System.out.println(" Expected: Sum=0000, Carry=1");
 }
}
